using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace Store.Tests;

[TestClass]
public sealed class ShoppingCartTests
{
    private ShoppingCart _cart = null!;

    [TestInitialize]
    public void Setup()
    {
        _cart = new ShoppingCart();
    }

    #region AddItem Tests

    [TestMethod]
    public void AddItem_SingleItem_CanCalculateTotal()
    {
        // Arrange & Act
        _cart.AddItem("SKU001", 2, 10.00m);

        // Assert
        Assert.AreEqual(20.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void AddItem_MultipleItems_AllIncludedInTotal()
    {
        // Arrange & Act
        _cart.AddItem("SKU001", 1, 10.00m);
        _cart.AddItem("SKU002", 3, 5.00m);

        // Assert
        Assert.AreEqual(25.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void AddItem_DuplicateSku_UpdatesQuantity()
    {
        // Arrange & Act
        _cart.AddItem("SKU001", 2, 10.00m);
        _cart.AddItem("SKU001", 3, 10.00m);

        // Assert — quantity should be 2+3=5, so total = 5*10 = 50
        Assert.AreEqual(50.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void AddItem_DuplicateSku_UpdatesPriceToLatest()
    {
        // Arrange & Act
        _cart.AddItem("SKU001", 2, 10.00m);
        _cart.AddItem("SKU001", 1, 15.00m);

        // Assert — quantity=3, price=15 (latest), total=3*15=45
        Assert.AreEqual(45.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void AddItem_ZeroQuantity_AddsItemWithZeroContribution()
    {
        // Arrange & Act
        _cart.AddItem("SKU001", 0, 10.00m);

        // Assert
        Assert.AreEqual(0.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void AddItem_NegativePrice_AllowsNegativeTotal()
    {
        // Arrange & Act
        _cart.AddItem("SKU001", 1, -5.00m);

        // Assert
        Assert.AreEqual(-5.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    [DataRow(null, DisplayName = "Null SKU")]
    [DataRow("", DisplayName = "Empty SKU")]
    public void AddItem_NullOrEmptySku_ThrowsArgumentException(string? sku)
    {
        // Act & Assert
        Assert.ThrowsException<ArgumentException>(() => _cart.AddItem(sku!, 1, 10.00m));
    }

    #endregion

    #region RemoveItem Tests

    [TestMethod]
    public void RemoveItem_ExistingItem_RemovesFromCart()
    {
        // Arrange
        _cart.AddItem("SKU001", 2, 10.00m);
        _cart.AddItem("SKU002", 1, 5.00m);

        // Act
        _cart.RemoveItem("SKU001");

        // Assert
        Assert.AreEqual(5.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void RemoveItem_NonExistentSku_ThrowsArgumentException()
    {
        // Arrange
        _cart.AddItem("SKU001", 1, 10.00m);

        // Act & Assert
        var ex = Assert.ThrowsException<ArgumentException>(() => _cart.RemoveItem("INVALID"));
        Assert.IsTrue(ex.Message.Contains("INVALID"));
    }

    [TestMethod]
    public void RemoveItem_EmptyCart_ThrowsArgumentException()
    {
        // Act & Assert
        Assert.ThrowsException<ArgumentException>(() => _cart.RemoveItem("SKU001"));
    }

    [TestMethod]
    [DataRow(null, DisplayName = "Null SKU")]
    [DataRow("", DisplayName = "Empty SKU")]
    public void RemoveItem_NullOrEmptySku_ThrowsArgumentException(string? sku)
    {
        // Act & Assert
        Assert.ThrowsException<ArgumentException>(() => _cart.RemoveItem(sku!));
    }

    #endregion

    #region CalculateTotal Tests

    [TestMethod]
    public void CalculateTotal_EmptyCart_ReturnsZero()
    {
        // Act & Assert
        Assert.AreEqual(0.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void CalculateTotal_SingleItem_ReturnsQuantityTimesPrice()
    {
        // Arrange
        _cart.AddItem("SKU001", 3, 7.50m);

        // Act
        var total = _cart.CalculateTotal();

        // Assert
        Assert.AreEqual(22.50m, total);
    }

    [TestMethod]
    public void CalculateTotal_MultipleItems_ReturnsSumOfAll()
    {
        // Arrange
        _cart.AddItem("SKU001", 2, 10.00m); // 20
        _cart.AddItem("SKU002", 1, 15.00m); // 15
        _cart.AddItem("SKU003", 4, 2.50m);  // 10

        // Act
        var total = _cart.CalculateTotal();

        // Assert
        Assert.AreEqual(45.00m, total);
    }

    [TestMethod]
    public void CalculateTotal_AfterRemoval_ExcludesRemovedItem()
    {
        // Arrange
        _cart.AddItem("SKU001", 2, 10.00m); // 20
        _cart.AddItem("SKU002", 1, 5.00m);  // 5
        _cart.RemoveItem("SKU001");

        // Act
        var total = _cart.CalculateTotal();

        // Assert
        Assert.AreEqual(5.00m, total);
    }

    [TestMethod]
    public void CalculateTotal_WithDecimalPrices_CalculatesCorrectly()
    {
        // Arrange
        _cart.AddItem("SKU001", 3, 9.99m);

        // Act
        var total = _cart.CalculateTotal();

        // Assert
        Assert.AreEqual(29.97m, total);
    }

    #endregion

    #region ApplyCoupon Tests

    [TestMethod]
    public void ApplyCoupon_Save10_Applies10PercentDiscount()
    {
        // Arrange
        _cart.AddItem("SKU001", 1, 100.00m);

        // Act
        _cart.ApplyCoupon("SAVE10");

        // Assert
        Assert.AreEqual(90.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void ApplyCoupon_Save20_Applies20PercentDiscount()
    {
        // Arrange
        _cart.AddItem("SKU001", 1, 100.00m);

        // Act
        _cart.ApplyCoupon("SAVE20");

        // Assert
        Assert.AreEqual(80.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void ApplyCoupon_InvalidCode_ThrowsArgumentException()
    {
        // Act & Assert
        var ex = Assert.ThrowsException<ArgumentException>(() => _cart.ApplyCoupon("INVALID"));
        Assert.IsTrue(ex.Message.Contains("INVALID"));
    }

    [TestMethod]
    [DataRow(null, DisplayName = "Null code")]
    [DataRow("", DisplayName = "Empty code")]
    public void ApplyCoupon_NullOrEmptyCode_ThrowsArgumentException(string? code)
    {
        // Act & Assert
        Assert.ThrowsException<ArgumentException>(() => _cart.ApplyCoupon(code!));
    }

    [TestMethod]
    public void ApplyCoupon_AppliedBeforeAddingItems_DiscountsTotal()
    {
        // Arrange
        _cart.ApplyCoupon("SAVE10");

        // Act
        _cart.AddItem("SKU001", 2, 50.00m);

        // Assert
        Assert.AreEqual(90.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void ApplyCoupon_SecondCouponOverridesFirst()
    {
        // Arrange
        _cart.AddItem("SKU001", 1, 100.00m);
        _cart.ApplyCoupon("SAVE10");

        // Act
        _cart.ApplyCoupon("SAVE20");

        // Assert
        Assert.AreEqual(80.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void ApplyCoupon_Save10_MultipleItems_DiscountsEntireTotal()
    {
        // Arrange
        _cart.AddItem("SKU001", 2, 25.00m); // 50
        _cart.AddItem("SKU002", 1, 30.00m); // 30
        // Subtotal = 80

        // Act
        _cart.ApplyCoupon("SAVE10");

        // Assert — 80 - 10% = 72
        Assert.AreEqual(72.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void ApplyCoupon_EmptyCart_TotalRemainsZero()
    {
        // Arrange & Act
        _cart.ApplyCoupon("SAVE20");

        // Assert
        Assert.AreEqual(0.00m, _cart.CalculateTotal());
    }

    #endregion

    #region Edge Cases

    [TestMethod]
    public void AddItem_LargeQuantity_CalculatesCorrectly()
    {
        // Arrange & Act
        _cart.AddItem("SKU001", 10000, 1.99m);

        // Assert
        Assert.AreEqual(19900.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void AddItem_VerySmallPrice_CalculatesCorrectly()
    {
        // Arrange & Act
        _cart.AddItem("SKU001", 1, 0.01m);

        // Assert
        Assert.AreEqual(0.01m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void RemoveItem_ThenReaddSameSku_Works()
    {
        // Arrange
        _cart.AddItem("SKU001", 2, 10.00m);
        _cart.RemoveItem("SKU001");

        // Act
        _cart.AddItem("SKU001", 1, 20.00m);

        // Assert
        Assert.AreEqual(20.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    [DataRow("save10", DisplayName = "Lowercase")]
    [DataRow("Save10", DisplayName = "Mixed case")]
    [DataRow("SAVE10 ", DisplayName = "Trailing space")]
    public void ApplyCoupon_CaseSensitive_InvalidVariantsThrow(string code)
    {
        // Act & Assert
        Assert.ThrowsException<ArgumentException>(() => _cart.ApplyCoupon(code));
    }

    #endregion
}

